/**
 * Typed agent event vocabulary. The wire format flowing through
 * `/api/plugin/events` (push, poll, SSE stream) is constrained to this
 * union; both bitfab-web and bitfab-plugin-lib reference these types.
 *
 * Add a new event type by extending `AgentEventDataMap`. Producers
 * (plugins, server) get full type checking on the data shape; consumers
 * (browser hook subscribers, plugin pollers) narrow on `event.type`.
 */
export interface AgentEventDataMap {
    "agent:navigate": {
        path: string;
    };
    "studio:return-to-agent": Record<string, never>;
    "studio:session-ended": Record<string, never>;
}
export type AgentEventType = keyof AgentEventDataMap & string;
export type AgentEventPayload = {
    [K in keyof AgentEventDataMap]: {
        type: K;
        data: AgentEventDataMap[K];
    };
}[keyof AgentEventDataMap];
export type AgentEvent = {
    [K in keyof AgentEventDataMap]: {
        id: string;
        type: K;
        data: AgentEventDataMap[K];
    };
}[keyof AgentEventDataMap];
